const{exec}=require("child_process");const fs=require("fs");const path=require("path");const util=require("util");const execAsync=util.promisify(exec);const PENDING_BUILD_FILE=path.join(__dirname,"../gemini-bridge/.pending-build.json");const BUILD_THRESHOLD=3;function loadPendingBuild(){try{if(fs.existsSync(PENDING_BUILD_FILE)){return JSON.parse(fs.readFileSync(PENDING_BUILD_FILE,"utf8"))}}catch(_){}return{files:[],lastCheck:0}}function savePendingBuild(state){try{const dir=path.dirname(PENDING_BUILD_FILE);if(!fs.existsSync(dir))fs.mkdirSync(dir,{recursive:true});fs.writeFileSync(PENDING_BUILD_FILE,JSON.stringify(state,null,2),"utf8")}catch(_){}}function clearPendingBuild(){savePendingBuild({files:[],lastCheck:Date.now()})}async function onPostToolUse(context){try{const editedFiles=context.editedFiles||[];if(editedFiles.length===0){return}const javaFiles=editedFiles.filter(f=>f.endsWith(".java"));if(javaFiles.length===0){return}const pending=loadPendingBuild();for(const f of javaFiles){if(!pending.files.includes(f)){pending.files.push(f)}}savePendingBuild(pending);if(pending.files.length<BUILD_THRESHOLD){console.log(`[BuildChecker] ${pending.files.length}/${BUILD_THRESHOLD} Java files changed. Build deferred.`);return}const editedModules=getEditedModules(pending.files);if(editedModules.size===0){return}console.log("\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");console.log("BUILD VERIFICATION (deferred)");console.log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");console.log(`Accumulated ${pending.files.length} Java file(s)\n`);for(const modulePath of editedModules){await checkBuild(modulePath)}clearPendingBuild();console.log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n")}catch(error){console.error("[BuildChecker] Error:",error.message)}}function getEditedModules(files){const modules=new Set;for(const filePath of files){if(!filePath.endsWith(".java")){continue}const match=filePath.match(/(KiiPS-[A-Z]+|KIIPS-[A-Z]+)/);if(match){const moduleName=match[1];modules.add(moduleName)}}return modules}async function checkBuild(moduleName){console.log(`🔨 Running build for ${moduleName}...`);const kiipsRoot=path.resolve(__dirname,"../..");const kiipsHub=path.join(kiipsRoot,"KiiPS-HUB");try{const{stdout,stderr}=await execAsync(`mvn clean compile -pl :${moduleName} -am -DskipTests`,{cwd:kiipsHub,timeout:12e4,env:{...process.env,JAVA_HOME:process.env.JAVA_HOME||"/Library/Java/JavaVirtualMachines/jdk-1.8.jdk/Contents/Home"}});if(stdout.includes("BUILD SUCCESS")){console.log(`✅ Build successful in ${moduleName}`);return}const errors=extractBuildErrors(stderr+stdout);if(errors.length===0){console.log(`⚠️  Build completed with warnings in ${moduleName}`)}else if(errors.length<5){console.log(`\n❌ Build failed in ${moduleName}:\n`);errors.forEach((error,index)=>{console.log(`${index+1}. ${error}`)});console.log("\n💡 Please fix these errors before continuing.\n")}else{console.log(`\n❌ ${errors.length} compilation errors found in ${moduleName}!`);console.log("💡 Consider reviewing the changes or running build manually:\n");console.log(`   cd KiiPS-HUB && mvn clean compile -pl :${moduleName} -am\n`)}}catch(error){if(error.code==="ETIMEDOUT"){console.log(`⏱️  Build timeout for ${moduleName} (exceeded 120s)`)}else{console.log(`❌ Build error for ${moduleName}: ${error.message}`);console.log("💡 Ensure JAVA_HOME is set and Maven is available")}}}function extractBuildErrors(output){const errors=[];const lines=output.split("\n");for(let i=0;i<lines.length;i++){const line=lines[i];if(line.includes("[ERROR]")&&line.includes(".java:")){const match=line.match(/\[ERROR\]\s+(.+\.java):\[(\d+),(\d+)\]\s+(.+)/);if(match){const[,file,lineNum,col,message]=match;const fileName=path.basename(file);errors.push(`${fileName}:${lineNum} - ${message.trim()}`)}}}return errors.slice(0,10)}if(require.main===module){let input="";process.stdin.setEncoding("utf8");process.stdin.on("data",chunk=>{input+=chunk});process.stdin.on("end",async()=>{try{const event=JSON.parse(input);const filePath=(event.tool_input||{}).file_path||"";const context={editedFiles:filePath?[filePath]:[]};await onPostToolUse(context);process.exit(0)}catch(e){process.stderr.write(`[BuildChecker] Parse error: ${e.message}\n`);process.exit(0)}});setTimeout(()=>{process.exit(0)},15e4)}module.exports={onPostToolUse:onPostToolUse};